cat > /tmp/find.mjs <<'EOF'
function buggy(lines, d){let t=0;for(const l of lines)t+=Math.round(l.unitCents*l.qty*(1-d/100));return t;}
function correct(lines, d){let sub=0;for(const l of lines)sub+=l.unitCents*l.qty;return Math.round(sub*(1-d/100));}
// search 2-line cases producing buggy=900, correct=899
for(let d of [5,10,15,20,25]){
 for(let a=1;a<1000;a++)for(let b=a;b<1000;b++){
   const lines=[{unitCents:a,qty:1},{unitCents:b,qty:1}];
   if(buggy(lines,d)===900 && correct(lines,d)===899){
     console.log(`d=${d} a=${a} b=${b} sub=${a+b}`);
   }
 }
}
EOF
